@namespace Lumeo
@implements IAsyncDisposable

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<Popover @bind-Open="_isOpen">
    <PopoverTrigger>
        <button type="button"
                id="@FormFieldControlId"
                name="@Name"
                aria-required="@Required.ToString().ToLower()"
                aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                aria-describedby="@FormFieldDescribedBy"
                class="@CssClass"
                disabled="@Disabled"
                @attributes="EffectiveAttributes">
            <SvgGlyph Svg="@(LumeoIcons.Calendar)" class="me-2 h-4 w-4 shrink-0" />
            @if (Value.HasValue)
            {
                <span>@FormatDateTime(Value.Value)</span>
                @if (ShowTimeZoneLabel && TimeZone is not null)
                {
                    <span class="ms-2 text-xs text-muted-foreground">@FormatZoneLabel(Value.Value)</span>
                }
            }
            else
            {
                <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
            }
            @if (Clearable && Value.HasValue)
            {
                <button type="button" class="ms-auto ps-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["DateTimePicker.ClearDate"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                    <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5" />
                </button>
            }
        </button>
    </PopoverTrigger>
    <PopoverContent Align="Lumeo.Align.Start" Class="w-auto p-0">
        <div class="flex">
            <div>
                <Calendar Value="@_dateValue" ValueChanged="HandleDateChanged"
                  MinDate="@(MinDate.HasValue ? (DateOnly?)DateOnly.FromDateTime(MinDate.Value) : null)"
                  MaxDate="@(MaxDate.HasValue ? (DateOnly?)DateOnly.FromDateTime(MaxDate.Value) : null)"
                  IsDateDisabled="@IsDateDisabled"
                  FirstDayOfWeek="@FirstDayOfWeek" />
            </div>
            <div class="border-s border-border/40">
                <div class="p-3 pb-1">
                    <span class="text-xs font-medium text-muted-foreground">@L["DateTimePicker.TimeLabel"]</span>
                </div>
                <div class="flex divide-x divide-border/40">
                    @* Hours column *@
                    <div id="@_hoursColId" role="listbox" aria-label="@L["TimePicker.HoursLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                        @{
                            var hours = GetHours();
                            var hoursRovingRoot = RovingRoot(_hoursColId, hours, _timeValue.HasValue ? GetDisplayHour(_timeValue.Value) : (int?)null);
                        }
                        @foreach (var hour in hours)
                        {
                            var h = hour;
                            var isSelected = _timeValue.HasValue && GetDisplayHour(_timeValue.Value) == h;
                            var disabled = IsHourDisabled(h);
                            <button type="button" id="@ColItemId(_hoursColId, h)" role="option"
                                    aria-selected="@(isSelected ? "true" : "false")"
                                    tabindex="@(h == hoursRovingRoot ? "0" : "-1")"
                                    disabled="@disabled"
                                    class="@TimeItemClass(isSelected)"
                                    @onclick="() => SelectHour(h)"
                                    @onkeydown="e => HandleColumnKeyDown(e, _hoursColId, hours, h)">
                                @h.ToString("D2")
                            </button>
                        }
                    </div>

                    @* Minutes column *@
                    <div id="@_minutesColId" role="listbox" aria-label="@L["TimePicker.MinutesLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                        @{
                            var minutes = GetMinutes();
                            // A Value whose minute isn't a multiple of MinuteStep lists no
                            // exact match — snap selection to the nearest listed step so the
                            // option still highlights and seeds the column's roving tab stop.
                            var selectedMinute = _timeValue.HasValue ? NearestListed(minutes, _timeValue.Value.Minutes) : (int?)null;
                            var minutesRovingRoot = RovingRoot(_minutesColId, minutes, selectedMinute);
                        }
                        @foreach (var minute in minutes)
                        {
                            var m = minute;
                            var isSelected = selectedMinute == m;
                            var disabled = IsMinuteDisabled(m);
                            <button type="button" id="@ColItemId(_minutesColId, m)" role="option"
                                    aria-selected="@(isSelected ? "true" : "false")"
                                    tabindex="@(m == minutesRovingRoot ? "0" : "-1")"
                                    disabled="@disabled"
                                    class="@TimeItemClass(isSelected)"
                                    @onclick="() => SelectMinute(m)"
                                    @onkeydown="e => HandleColumnKeyDown(e, _minutesColId, minutes, m)">
                                @m.ToString("D2")
                            </button>
                        }
                    </div>

                    @* Seconds column *@
                    @if (ShowSeconds)
                    {
                        <div id="@_secondsColId" role="listbox" aria-label="@L["TimePicker.SecondsLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                            @{
                                var seconds = GetSeconds();
                                // Same nearest-step snap as minutes: a Value whose second isn't
                                // a multiple of SecondStep would otherwise highlight nothing.
                                var selectedSecond = _timeValue.HasValue ? NearestListed(seconds, _timeValue.Value.Seconds) : (int?)null;
                                var secondsRovingRoot = RovingRoot(_secondsColId, seconds, selectedSecond);
                            }
                            @foreach (var second in seconds)
                            {
                                var s = second;
                                var isSelected = selectedSecond == s;
                                var disabled = IsSecondDisabled(s);
                                <button type="button" id="@ColItemId(_secondsColId, s)" role="option"
                                        aria-selected="@(isSelected ? "true" : "false")"
                                        tabindex="@(s == secondsRovingRoot ? "0" : "-1")"
                                        disabled="@disabled"
                                        class="@TimeItemClass(isSelected)"
                                        @onclick="() => SelectSecond(s)"
                                        @onkeydown="e => HandleColumnKeyDown(e, _secondsColId, seconds, s)">
                                    @s.ToString("D2")
                                </button>
                            }
                        </div>
                    }

                    @* AM/PM column *@
                    @if (!Use24Hour)
                    {
                        <div class="flex flex-col py-1">
                            @{
                                var isAm = !_timeValue.HasValue || _timeValue.Value.Hours < 12;
                                var amLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.AMDesignator) ? "AM" : EffectiveCulture.DateTimeFormat.AMDesignator;
                                var pmLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.PMDesignator) ? "PM" : EffectiveCulture.DateTimeFormat.PMDesignator;
                            }
                            <button type="button"
                                    aria-pressed="@(isAm ? "true" : "false")"
                                    class="@TimeItemClass(isAm)"
                                    @onclick="() => SelectAmPm(true)">
                                @amLabel
                            </button>
                            <button type="button"
                                    aria-pressed="@((!isAm) ? "true" : "false")"
                                    class="@TimeItemClass(!isAm)"
                                    @onclick="() => SelectAmPm(false)">
                                @pmLabel
                            </button>
                        </div>
                    }
                </div>
            </div>
        </div>
    </PopoverContent>
</Popover>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>Marks the field required, rendering a trailing asterisk on <see cref="Label"/>
    /// and setting <c>aria-required</c> on the trigger button.</summary>
    [Parameter] public bool Required { get; set; }
    /// <summary>Forces the invalid (error) visual state — a destructive border/ring — even
    /// when not inside a <c>FormField</c> reporting an error. ORed with the ambient
    /// <c>FormField</c> error state.</summary>
    [Parameter] public bool Invalid { get; set; }
    /// <summary>Error message shown below the field when invalid. Only rendered when this
    /// picker is standalone (outside a <c>FormField</c>, which owns its own error slot).</summary>
    [Parameter] public string? ErrorText { get; set; }
    /// <summary>Helper text shown below the field when not invalid. Only rendered when this
    /// picker is standalone (outside a <c>FormField</c>).</summary>
    [Parameter] public string? HelperText { get; set; }
    /// <summary>Field label rendered above the trigger button. Suppressed when nested inside
    /// a <c>FormField</c>, which renders its own label.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>The trigger button's <c>name</c> attribute, for form submission/identification.</summary>
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField the generated id must own this element so the FormField <Label For> (and any
    // interop keyed off the id) stays valid; a consumer-splatted id in AdditionalAttributes renders after
    // the explicit id= and would override it. Strip it here when InsideFormField; outside, pass through.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    /// <summary>The selected local date and time. Two-way bindable via
    /// <see cref="ValueChanged"/>; also derivable from/to <see cref="OffsetValue"/> when a
    /// <see cref="TimeZone"/> is configured.</summary>
    [Parameter] public DateTime? Value { get; set; }
    /// <summary>Raised when the user picks a date or time (or clears via
    /// <see cref="Clearable"/>) with the new <see cref="Value"/>.</summary>
    [Parameter] public EventCallback<DateTime?> ValueChanged { get; set; }

    /// <summary>
    /// Optional <see cref="DateTimeOffset"/> binding. When the caller binds this,
    /// it takes precedence: writes flow back through <see cref="OffsetValueChanged"/>
    /// with the offset that matches <see cref="TimeZone"/> at the picked wall-clock
    /// time (DST-aware). The plain <see cref="ValueChanged"/> still fires for back-compat.
    /// Recommended over <see cref="Value"/> when working with multi-zone scenarios.
    /// </summary>
    [Parameter] public DateTimeOffset? OffsetValue { get; set; }
    /// <summary>Raised alongside <see cref="ValueChanged"/> with the offset-aware instant
    /// (DST-adjusted for <see cref="TimeZone"/>) whenever the picked value changes.</summary>
    [Parameter] public EventCallback<DateTimeOffset?> OffsetValueChanged { get; set; }

    /// <summary>
    /// When non-null, all display/edit happens in this zone — the user picks a
    /// wall-clock instant in that zone, and the emitted <see cref="DateTimeOffset"/>
    /// carries the matching offset for that instant (DST-aware). When null, the
    /// picker behaves exactly as before (local time, no zone indicator).
    /// </summary>
    [Parameter] public TimeZoneInfo? TimeZone { get; set; }

    /// <summary>
    /// When true (default) and <see cref="TimeZone"/> is set, renders a small
    /// "Europe/Berlin (UTC+1)"-style indicator next to the value.
    /// </summary>
    [Parameter] public bool ShowTimeZoneLabel { get; set; } = true;

    /// <summary>Shows 24-hour time (00-23) instead of a 12-hour clock with an AM/PM column.
    /// Default <c>true</c>.</summary>
    [Parameter] public bool Use24Hour { get; set; } = true;
    /// <summary>Adds a seconds column to the time picker. Default <c>false</c> (minute
    /// precision).</summary>
    [Parameter] public bool ShowSeconds { get; set; }
    /// <summary>Minute column increment. <c>1</c> (default) lists every minute;
    /// <c>5</c>/<c>15</c> etc. list only multiples of the step.</summary>
    [Parameter] public int MinuteStep { get; set; } = 1;
    /// <summary>Second column increment (only relevant when <see cref="ShowSeconds"/>
    /// is true). Defaults to <c>1</c>.</summary>
    [Parameter] public int SecondStep { get; set; } = 1;
    /// <summary>
    /// Date portion format. When null (default) falls back to the effective culture's
    /// <c>ShortDatePattern</c>.
    /// </summary>
    [Parameter] public string? DateFormat { get; set; }
    /// <summary>Placeholder shown on the trigger button when no value is selected.
    /// Falls back to the localized "DateTimePicker.Placeholder" string when null.</summary>
    [Parameter] public string? Placeholder { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// date/time formatting. Leave null to honour ASP.NET request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    private string EffectiveDateFormat => DateFormat ?? EffectiveCulture.DateTimeFormat.ShortDatePattern;

    private string EffectivePlaceholder => Placeholder ?? L["DateTimePicker.Placeholder"];
    /// <summary>Disables the trigger button, preventing the popover from opening.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Shows a trailing clear (X) button on the trigger when a value is selected,
    /// letting the user reset <see cref="Value"/> to <c>null</c>.</summary>
    [Parameter] public bool Clearable { get; set; }
    /// <summary>Earliest selectable date/time. Forwarded to the embedded calendar's date
    /// gate; on the boundary day, also disables times before <c>MinDate</c>'s time-of-day.</summary>
    [Parameter] public DateTime? MinDate { get; set; }
    /// <summary>Latest selectable date/time. Forwarded to the embedded calendar's date
    /// gate; on the boundary day, also disables times after <c>MaxDate</c>'s time-of-day.</summary>
    [Parameter] public DateTime? MaxDate { get; set; }
    /// <summary>Per-date predicate returning <c>true</c> to disable a specific date in the
    /// embedded calendar, independent of <see cref="MinDate"/>/<see cref="MaxDate"/>.</summary>
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    /// <summary>
    /// Override the locale-derived first day of week shown by the embedded calendar.
    /// Forwarded to the inner <see cref="Calendar"/>; leave null to fall back to
    /// <see cref="System.Globalization.CultureInfo.CurrentCulture"/>.
    /// </summary>
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }
    /// <summary>Additional CSS classes merged onto the trigger button.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the trigger button.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isOpen;
    private DateOnly? _dateValue;
    private TimeSpan? _timeValue;
    // Uncontrolled discriminator: the last Value we last SAW as an incoming PARAMETER
    // (regardless of who pushed it). Consulted only when ValueChanged has no delegate.
    private DateTime? _lastValueParam;
    // CONTROLLED discriminator: the last value WE pushed via ValueChanged (also
    // re-synced whenever we adopt an authoritative Value, including a Value derived
    // from OffsetValue/TimeZone below). A controlled parent re-render that echoes
    // back this exact value is safe to ignore (keep the optimistic _dateValue/
    // _timeValue); anything else (veto / normalization / reset) is authoritative and
    // wins. Mirrors Switch's _lastPushed discriminator.
    private DateTime? _lastValuePushed;
    // Same CONTROLLED/UNCONTROLLED split for the independently-bindable
    // OffsetValue/OffsetValueChanged pair.
    private DateTimeOffset? _lastOffsetValueParam;
    private DateTimeOffset? _lastOffsetValuePushed;
    private TimeZoneInfo? _prevTimeZone;

    private string CssClass => Cx.Merge("group flex h-9 w-full items-center rounded-md border", (EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input"), "bg-transparent px-3 py-2 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50", Class);

    protected override void OnParametersSet()
    {
        // When the parent binds OffsetValue and it changed — OR the TimeZone the
        // value is projected through changed — derive Value from OffsetValue by
        // projecting into the configured TimeZone (or local if null). Re-projecting
        // on a TimeZone change keeps the wall-clock display in step with the zone
        // label (FormatZoneLabel reads TimeZone live); otherwise a zone swap left
        // the displayed instant from the old zone while the label showed the new.
        //
        // CONTROLLED/UNCONTROLLED split (mirrors Switch): when OffsetValueChanged
        // has a delegate, an echo of our own last push (OffsetValue == _lastOffsetValuePushed)
        // is a no-op — anything else (veto, normalization, reset) is authoritative
        // and must win. When uncontrolled, only a genuinely new incoming literal
        // (vs. the last one we SAW as a parameter) triggers a re-projection.
        var offsetChanged = OffsetValueChanged.HasDelegate
            ? OffsetValue != _lastOffsetValuePushed
            : OffsetValue != _lastOffsetValueParam;
        var zoneChanged = !Equals(TimeZone, _prevTimeZone);
        if (offsetChanged || zoneChanged)
        {
            _lastOffsetValuePushed = OffsetValue;
            _prevTimeZone = TimeZone;
            if (OffsetValue.HasValue)
            {
                var local = TimeZone is null
                    ? OffsetValue.Value.LocalDateTime
                    : TimeZoneInfo.ConvertTime(OffsetValue.Value, TimeZone).DateTime;
                Value = DateTime.SpecifyKind(local, DateTimeKind.Unspecified);
            }
            else if (offsetChanged)
            {
                // Only the OffsetValue going null should clear Value; a bare
                // TimeZone change with no OffsetValue bound must not wipe a
                // plain Value-bound selection.
                Value = null;
            }
        }
        _lastOffsetValueParam = OffsetValue;

        // Resync the internal date/time selection only when the bound Value
        // genuinely changed. A time picked before any date lives solely in
        // _timeValue (UpdateValue can't commit without a date) — resyncing
        // unconditionally meant any parent re-render wiped that pending
        // selection back to the (null) Value.
        //
        // Same CONTROLLED/UNCONTROLLED split as above, applied to Value itself:
        // CONTROLLED — echo of our own push (Value == _lastValuePushed) keeps the
        // in-flight _dateValue/_timeValue; anything else (veto / normalization /
        // reset, or the offset-derivation above) is authoritative and wins.
        // UNCONTROLLED — adopt only when the parent genuinely changes the literal
        // Value it supplies; a stale re-render with the same literal must not
        // clobber the user's pending pick.
        var valueChanged = ValueChanged.HasDelegate
            ? Value != _lastValuePushed
            : Value != _lastValueParam;
        if (valueChanged)
        {
            _lastValuePushed = Value;
            if (Value.HasValue)
            {
                _dateValue = DateOnly.FromDateTime(Value.Value);
                _timeValue = Value.Value.TimeOfDay;
            }
            else
            {
                _dateValue = null;
                _timeValue = null;
            }
        }
        _lastValueParam = Value;
    }

    private string FormatZoneLabel(DateTime wallClock)
    {
        if (TimeZone is null) return string.Empty;
        var unspecified = DateTime.SpecifyKind(wallClock, DateTimeKind.Unspecified);
        var offset = TimeZone.GetUtcOffset(unspecified);
        var sign = offset.Ticks >= 0 ? "+" : "-";
        var abs = offset.Duration();
        var offsetText = abs.Minutes == 0
            ? $"UTC{sign}{abs.Hours}"
            : $"UTC{sign}{abs.Hours}:{abs.Minutes:D2}";
        return $"{TimeZone.Id} ({offsetText})";
    }

    private DateTimeOffset? ToOffset(DateTime? wallClock)
    {
        if (!wallClock.HasValue) return null;
        var unspecified = DateTime.SpecifyKind(wallClock.Value, DateTimeKind.Unspecified);
        if (TimeZone is null)
        {
            // Treat as local — preserve historic behaviour.
            return new DateTimeOffset(DateTime.SpecifyKind(wallClock.Value, DateTimeKind.Local));
        }
        var offset = TimeZone.GetUtcOffset(unspecified);
        return new DateTimeOffset(unspecified, offset);
    }

    private string FormatDateTime(DateTime dt)
    {
        var timeFormat = Use24Hour
            ? (ShowSeconds ? "HH:mm:ss" : "HH:mm")
            : (ShowSeconds ? "hh:mm:ss tt" : "hh:mm tt");
        return $"{dt.ToString(EffectiveDateFormat, EffectiveCulture)} {dt.ToString(timeFormat, EffectiveCulture)}";
    }

    private List<int> GetHours()
    {
        var hours = new List<int>();
        if (Use24Hour)
        {
            for (var i = 0; i < 24; i++) hours.Add(i);
        }
        else
        {
            for (var i = 1; i <= 12; i++) hours.Add(i);
        }
        return hours;
    }

    private int GetDisplayHour(TimeSpan time)
    {
        if (Use24Hour) return time.Hours;
        var h = time.Hours % 12;
        return h == 0 ? 12 : h;
    }

    private List<int> GetMinutes()
    {
        var minutes = new List<int>();
        var step = Math.Max(1, MinuteStep);
        for (var i = 0; i < 60; i += step) minutes.Add(i);
        return minutes;
    }

    private List<int> GetSeconds()
    {
        var seconds = new List<int>();
        var step = Math.Max(1, SecondStep);
        for (var i = 0; i < 60; i += step) seconds.Add(i);
        return seconds;
    }

    private static string TimeItemClass(bool isSelected) =>
        isSelected
            ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-40"
            : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50 disabled:pointer-events-none disabled:opacity-40";

    // ---- Date-aware Min/Max enforcement on the time columns (#208) ----
    // The bounds only bite on the boundary day: if the selected date equals
    // MinDate's date, times before MinDate's time-of-day are disabled; likewise
    // MaxDate caps the time on its date. On days strictly inside the range the
    // whole clock is selectable. With no date picked yet we can't know which
    // day applies, so nothing is disabled (the calendar already gates the date).
    private TimeSpan? MinTimeForSelectedDate
    {
        get
        {
            if (!MinDate.HasValue || !_dateValue.HasValue) return null;
            return _dateValue.Value == DateOnly.FromDateTime(MinDate.Value) ? MinDate.Value.TimeOfDay : null;
        }
    }

    private TimeSpan? MaxTimeForSelectedDate
    {
        get
        {
            if (!MaxDate.HasValue || !_dateValue.HasValue) return null;
            return _dateValue.Value == DateOnly.FromDateTime(MaxDate.Value) ? MaxDate.Value.TimeOfDay : null;
        }
    }

    private bool IsHourDisabled(int displayHour)
    {
        var h24 = DisplayHourTo24(displayHour);
        var hourStart = new TimeSpan(h24, 0, 0);
        var hourEnd = new TimeSpan(h24, 59, ShowSeconds ? 59 : 0);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && hourEnd < min.Value) return true;
        if (max.HasValue && hourStart > max.Value) return true;
        return false;
    }

    private bool IsMinuteDisabled(int minute)
    {
        var h = (_timeValue ?? TimeSpan.Zero).Hours;
        var minStart = new TimeSpan(0, h, minute, 0);
        var minEnd = new TimeSpan(0, h, minute, ShowSeconds ? 59 : 0);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && minEnd < min.Value) return true;
        if (max.HasValue && minStart > max.Value) return true;
        return false;
    }

    private bool IsSecondDisabled(int second)
    {
        var current = _timeValue ?? TimeSpan.Zero;
        var candidate = new TimeSpan(0, current.Hours, current.Minutes, second);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && candidate < min.Value) return true;
        if (max.HasValue && candidate > max.Value) return true;
        return false;
    }

    private int DisplayHourTo24(int displayHour)
    {
        if (Use24Hour) return displayHour;
        var isPm = (_timeValue ?? TimeSpan.Zero).Hours >= 12;
        var h = displayHour % 12;
        return isPm ? h + 12 : h;
    }

    private async Task HandleDateChanged(DateOnly? date)
    {
        _dateValue = date;
        await UpdateValue();
    }

    private async Task SelectHour(int hour)
    {
        if (IsHourDisabled(hour)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        int actualHour;
        if (Use24Hour)
        {
            actualHour = hour;
        }
        else
        {
            var isPm = current.Hours >= 12;
            actualHour = hour % 12;
            if (isPm) actualHour += 12;
        }
        _timeValue = new TimeSpan(actualHour, current.Minutes, current.Seconds);
        await UpdateValue();
    }

    private async Task SelectMinute(int minute)
    {
        if (IsMinuteDisabled(minute)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        _timeValue = new TimeSpan(current.Hours, minute, current.Seconds);
        await UpdateValue();
    }

    private async Task SelectSecond(int second)
    {
        if (IsSecondDisabled(second)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        _timeValue = new TimeSpan(current.Hours, current.Minutes, second);
        await UpdateValue();
    }

    private async Task SelectAmPm(bool isAm)
    {
        var current = _timeValue ?? TimeSpan.Zero;
        var hour = current.Hours % 12;
        if (!isAm) hour += 12;
        _timeValue = new TimeSpan(hour, current.Minutes, current.Seconds);
        await UpdateValue();
    }

    // ---- Arrow-key list navigation (roving focus per time column) ----
    // Mirrors TimePicker so the DateTimePicker's time columns are keyboard-navigable
    // too: ArrowDown/Up move to the next/previous ENABLED option, Home/End jump to
    // the first/last enabled option, Enter/Space select. The arrow keys' page/column
    // scroll is suppressed via the prevent-default registration below.
    private readonly string _hoursColId = LumeoIds.New("dtp-hours");
    private readonly string _minutesColId = LumeoIds.New("dtp-minutes");
    private readonly string _secondsColId = LumeoIds.New("dtp-seconds");

    private static string ColItemId(string colId, int value) => $"{colId}-{value}";

    // Roving tab stop seed: each listbox must always expose exactly ONE tabbable
    // option so the column is keyboard-reachable. When a value is selected that
    // option is the tab stop; otherwise (e.g. _timeValue is null — no time picked
    // yet) seed the FIRST ENABLED option, falling back to the first option if every
    // option is disabled. Mirrors Calendar's EnsureFocusedDate idea. Returns null
    // only for an empty column. Note GetDisplayHour/Minutes/Seconds always emit a
    // value present in `values`, so a real selection wins here.
    // Snap an actual value to the nearest option present in a stepped column.
    // GetMinutes/GetSeconds only emit multiples of the step, so a Value of e.g.
    // 37 minutes with MinuteStep=15 matches none by exact equality — pick the
    // closest listed value (30, since |37-30|=7 < |37-45|=8) so the option still
    // highlights and the column keeps a seeded roving tab stop. On a tie the lower
    // value wins (stable).
    private static int? NearestListed(List<int> values, int actual)
    {
        if (values.Count == 0) return null;
        var best = values[0];
        var bestDist = Math.Abs(actual - best);
        foreach (var v in values)
        {
            var dist = Math.Abs(actual - v);
            if (dist < bestDist)
            {
                best = v;
                bestDist = dist;
            }
        }
        return best;
    }

    private int? RovingRoot(string colId, List<int> values, int? selected)
    {
        if (values.Count == 0) return null;
        // A selected, still-enabled option is the tab stop.
        if (selected.HasValue && values.Contains(selected.Value) && !IsColItemDisabled(colId, selected.Value))
            return selected.Value;
        // Otherwise (nothing selected, or the selection is now disabled) seed the
        // first ENABLED option so the column stays both keyboard-reachable and
        // actionable; fall back to the first option only if every option is disabled.
        foreach (var v in values)
        {
            if (!IsColItemDisabled(colId, v)) return v;
        }
        return values[0];
    }

    private async Task HandleColumnKeyDown(KeyboardEventArgs e, string colId, List<int> values, int current)
    {
        switch (e.Key)
        {
            case "ArrowDown": await FocusAdjacent(colId, values, current, +1); break;
            case "ArrowUp": await FocusAdjacent(colId, values, current, -1); break;
            case "Home": await FocusEdge(colId, values, fromStart: true); break;
            case "End": await FocusEdge(colId, values, fromStart: false); break;
            // Enter/Space are intentionally NOT handled here: each option is a native <button> with an
            // @onclick, so Enter/Space already activate it (the browser synthesizes a click → SelectHour/
            // Minute/Second). Handling them here too would fire the selection — and ValueChanged — twice
            // (Codex P3). Arrow/Home/End only move the roving focus.
        }
    }

    private async Task FocusAdjacent(string colId, List<int> values, int current, int step)
    {
        var idx = values.IndexOf(current);
        if (idx < 0) return;
        for (var i = idx + step; i >= 0 && i < values.Count; i += step)
        {
            if (!IsColItemDisabled(colId, values[i]))
            {
                await Interop.FocusElement(ColItemId(colId, values[i]));
                return;
            }
        }
    }

    private async Task FocusEdge(string colId, List<int> values, bool fromStart)
    {
        var ordered = fromStart ? values : Enumerable.Reverse(values).ToList();
        foreach (var v in ordered)
        {
            if (!IsColItemDisabled(colId, v))
            {
                await Interop.FocusElement(ColItemId(colId, v));
                return;
            }
        }
    }

    private bool IsColItemDisabled(string colId, int value)
    {
        if (colId == _hoursColId) return IsHourDisabled(value);
        if (colId == _minutesColId) return IsMinuteDisabled(value);
        if (colId == _secondsColId) return IsSecondDisabled(value);
        return false;
    }

    private bool _navKeysRegistered;
    // Captures whether the seconds column was registered AT registration time.
    // Unregistration must key off this snapshot, not the live ShowSeconds: toggling
    // ShowSeconds false while the popover is open would otherwise leave the seconds
    // column's prevent-default-keys handler-map entry registered forever (the
    // unregister branch reads ShowSeconds==false and skips it).
    private bool _secondsNavRegistered;
    private static readonly PreventDefaultKeyRule[] ColumnNavKeys =
    [
        new("ArrowUp"), new("ArrowDown"), new("Home"), new("End"),
    ];

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_isOpen && !_navKeysRegistered)
        {
            _navKeysRegistered = true;
            try
            {
                await Interop.RegisterPreventDefaultKeys(_hoursColId, ColumnNavKeys);
                await Interop.RegisterPreventDefaultKeys(_minutesColId, ColumnNavKeys);
                if (ShowSeconds)
                {
                    await Interop.RegisterPreventDefaultKeys(_secondsColId, ColumnNavKeys);
                    _secondsNavRegistered = true;
                }
            }
            catch (JSDisconnectedException) { _navKeysRegistered = false; }
            catch (InvalidOperationException) { _navKeysRegistered = false; } // prerender
        }
        else if (_isOpen && _navKeysRegistered && ShowSeconds && !_secondsNavRegistered)
        {
            // Seconds was enabled AFTER the popover (and the hour/minute columns) were
            // already registered — the open-time branch above won't run again, so register
            // the seconds column now. Otherwise Arrow/Home/End on the freshly rendered
            // seconds column scroll the page instead of being suppressed (Codex P2).
            try
            {
                await Interop.RegisterPreventDefaultKeys(_secondsColId, ColumnNavKeys);
                _secondsNavRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // prerender
        }
        else if (!_isOpen && _navKeysRegistered)
        {
            _navKeysRegistered = false;
            await UnregisterNavKeys();
        }
    }

    // Tear down the JS prevent-default key handlers registered for the time
    // columns. Mirrors TimePicker so a picker disposed while its popover is open
    // (route change, conditional form section) doesn't leak stale handler-map
    // entries for the generated column ids.
    private async Task UnregisterNavKeys()
    {
        // Unregister the seconds column off the captured registration flag, NOT the
        // live ShowSeconds: toggling ShowSeconds false while the popover is open would
        // otherwise skip this branch and leak the handler-map entry for the column id
        // we DID register on open. Reset the flag so a later reopen re-snapshots.
        var unregisterSeconds = _secondsNavRegistered;
        _secondsNavRegistered = false;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_hoursColId);
            await Interop.UnregisterPreventDefaultKeys(_minutesColId);
            if (unregisterSeconds) await Interop.UnregisterPreventDefaultKeys(_secondsColId);
        }
        // DisposeAsync routes through here, and a mid-navigation dispose can surface
        // ObjectDisposed/InvalidOperation from the JS layer — swallow all three, matching
        // the codebase dispose convention (Carousel/Rating/Segmented/ToggleGroup).
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_navKeysRegistered) await UnregisterNavKeys();
    }

    private async Task UpdateValue()
    {
        if (_dateValue.HasValue)
        {
            var time = _timeValue ?? TimeSpan.Zero;
            // Date-aware clamp: switching to a boundary day can leave a stale
            // time-of-day outside [MinDate, MaxDate]. The time columns gate clicks
            // via IsHour/Minute/SecondDisabled, but a date change carries the old
            // time across unchecked. Re-derive the per-day bounds against the new
            // _dateValue and clamp before committing, writing the clamped time back
            // into _timeValue so the columns and the committed Value agree.
            var minTod = MinTimeForSelectedDate;
            var maxTod = MaxTimeForSelectedDate;
            if (minTod.HasValue && time < minTod.Value) time = minTod.Value;
            if (maxTod.HasValue && time > maxTod.Value) time = maxTod.Value;
            _timeValue = time;
            var dt = _dateValue.Value.ToDateTime(new TimeOnly(time.Hours, time.Minutes, time.Seconds));
            // When a TimeZone is configured, the wall-clock value is zone-relative —
            // mark it Unspecified so callers don't mistake it for system-local.
            if (TimeZone is not null) dt = DateTime.SpecifyKind(dt, DateTimeKind.Unspecified);
            Value = dt;
            // Record _lastValuePushed BEFORE invoking ValueChanged: a controlled
            // parent re-renders synchronously inside InvokeAsync, so OnParametersSet
            // must already see this value as "the value we just pushed" to
            // distinguish an accepted echo (keep in-flight state) from a veto
            // (parent kept its old value → roll back).
            _lastValuePushed = dt;
            await ValueChanged.InvokeAsync(dt);

            if (OffsetValueChanged.HasDelegate)
            {
                var offset = ToOffset(dt);
                _lastOffsetValuePushed = offset;
                await OffsetValueChanged.InvokeAsync(offset);
            }
        }
    }

    private async Task HandleClear()
    {
        Value = null;
        _lastValuePushed = null;
        _dateValue = null;
        _timeValue = null;
        await ValueChanged.InvokeAsync(null);
        if (OffsetValueChanged.HasDelegate)
        {
            _lastOffsetValuePushed = null;
            await OffsetValueChanged.InvokeAsync(null);
        }
    }
}
